const Placements = () => {
    const { isOpen, onOpen, onClose } = useDisclosure();
    const [placement, setPlacement] = useState<any>("right");

    const openPlacement = (place: any) => {
      setPlacement(place);
      onOpen();
    };

    return (
        <div className="p-10 flex flex-col items-center gap-4">
            <h3
                className="text-lg font-semibold mb-2 text-neutral-800 dark:text-neutral-200">Try Different Placements
                        </h3>
            <div className="flex flex-wrap gap-3">
                <Button onClick={() => openPlacement("left")}>Left Drawer</Button>
                <Button onClick={() => openPlacement("right")}>Right Drawer</Button>
                <Button onClick={() => openPlacement("top")}>Top Drawer</Button>
                <Button onClick={() => openPlacement("bottom")}>Bottom Drawer</Button>
            </div>
            <Drawer backdrop="opaque" isOpen={isOpen} onClose={onClose} placement={placement}>
                <DrawerContent>
                    <DrawerHeader>Drawer placement: {placement}</DrawerHeader>
                    <DrawerBody>
                        <p className="text-neutral-600 dark:text-neutral-400">This drawer is sliding in from the <strong>{placement}</strong>edge of the window.
                                          </p>
                    </DrawerBody>
                    <DrawerFooter>
                        <Button onClick={onClose}>Close</Button>
                    </DrawerFooter>
                </DrawerContent>
            </Drawer>
        </div>
    );
};

const Sizes = () => {
    const { isOpen, onOpen, onClose } = useDisclosure();
    const [size, setSize] = useState<any>("md");
    const [placement, setPlacement] = useState<any>("right");

    const openSize = (sz: any, place: any = "right") => {
      setSize(sz);
      setPlacement(place);
      onOpen();
    };

    const sizes = ["xs", "sm", "md", "lg", "xl", "2xl", "3xl", "4xl", "5xl", "full"] as const;

    return (
        <div className="p-10 flex flex-col gap-8">
            <div>
                <h3
                    className="text-lg font-semibold mb-4 text-neutral-800 dark:text-neutral-200">Horizontal Sizes (sliding left/right)
                              </h3>
                <div className="flex flex-wrap gap-3">
                    {sizes.map((sz) => (
                      <Button key={sz} variant="bordered" onClick={() => openSize(sz, "right")}>
                        Size {sz.toUpperCase()}
                      </Button>
                    ))}
                </div>
            </div>
            <div>
                <h3
                    className="text-lg font-semibold mb-4 text-neutral-800 dark:text-neutral-200">Vertical Sizes (sliding top/bottom)
                              </h3>
                <div className="flex flex-wrap gap-3">
                    {sizes.slice(0, 5).map((sz) => (
                      <Button key={sz} variant="flat" color="secondary" onClick={() => openSize(sz, "bottom")}>
                        Size {sz.toUpperCase()} (Bottom)
                      </Button>
                    ))}
                    <Button
                        variant="flat"
                        color="secondary"
                        onClick={() => openSize("full", "bottom")}>Size FULL (Bottom)
                                    </Button>
                </div>
            </div>
            <Drawer
                backdrop="opaque"
                isOpen={isOpen}
                onClose={onClose}
                size={size}
                placement={placement}>
                <DrawerContent>
                    <DrawerHeader>Size: {size?.toUpperCase()}</DrawerHeader>
                    <DrawerBody>
                        <p className="text-neutral-600 dark:text-neutral-400">This drawer is size <strong>{size}</strong>, placed at <strong>{placement}</strong>.
