const CustomMotion = () => {
    const { isOpen, onOpen, onClose } = useDisclosure();
    const [motionType, setMotionType] = useState<"left-to-right" | "right-to-left" | "top-to-bottom" | "bottom-to-top">("left-to-right");

    const motionConfigs = {
      "left-to-right": {
        placement: "left" as const,
        motionProps: {
          variants: {
            initial: { x: "-100%" },
            animate: { x: 0, transition: { type: "spring" as const, stiffness: 300, damping: 30 } },
            exit: { x: "100vw", transition: { duration: 0.35, ease: "easeIn" as const } }
          }
        }
      },
      "right-to-left": {
        placement: "right" as const,
        motionProps: {
          variants: {
            initial: { x: "100%" },
            animate: { x: 0, transition: { type: "spring" as const, stiffness: 300, damping: 30 } },
            exit: { x: "-100vw", transition: { duration: 0.35, ease: "easeIn" as const } }
          }
        }
      },
      "top-to-bottom": {
        placement: "top" as const,
        motionProps: {
          variants: {
            initial: { y: "-100%" },
            animate: { y: 0, transition: { type: "spring" as const, stiffness: 300, damping: 30 } },
            exit: { y: "100vh", transition: { duration: 0.35, ease: "easeIn" as const } }
          }
        }
      },
      "bottom-to-top": {
        placement: "bottom" as const,
        motionProps: {
          variants: {
            initial: { y: "100%" },
            animate: { y: 0, transition: { type: "spring" as const, stiffness: 300, damping: 30 } },
            exit: { y: "-100vh", transition: { duration: 0.35, ease: "easeIn" as const } }
          }
        }
      }
    };

    const openMotion = (type: typeof motionType) => {
      setMotionType(type);
      onOpen();
    };

    const currentConfig = motionConfigs[motionType];

    return (
        <div className="p-10 flex flex-col items-center justify-center min-h-[300px]">
            <div className="text-center max-w-md mb-6">
                <h3
                    className="text-lg font-semibold mb-2 text-neutral-800 dark:text-neutral-200">Custom Motion Presets
                              </h3>
                <p className="text-sm text-neutral-500 mb-4">Showcase using <code>motionProps</code>to override entrance/exit animations. Open the drawer with one of the buttons below to see the different custom motion trajectories.
                              </p>
                <div className="flex flex-wrap justify-center gap-3">
                    <Button onClick={() => openMotion("left-to-right")}>Left to Right</Button>
                    <Button onClick={() => openMotion("right-to-left")}>Right to Left</Button>
                    <Button onClick={() => openMotion("top-to-bottom")}>Top to Bottom</Button>
                    <Button onClick={() => openMotion("bottom-to-top")}>Bottom to Top</Button>
                </div>
            </div>
            <Drawer
                size="md"
                isOpen={isOpen}
                onClose={onClose}
                placement={currentConfig.placement}
                motionProps={currentConfig.motionProps}>
                <DrawerContent>
                    <DrawerHeader>Custom Motion: {motionType.replace(/-/g, " ")}</DrawerHeader>
                    <DrawerBody>
                        <p className="text-neutral-600 dark:text-neutral-400">This drawer enters from the standard position and exits in a custom direction using custom motion variants!
                                          </p>
                        <div className="mt-4 text-neutral-500 text-xs">Custom configuration:
                                            <pre
                                className="mt-2 p-3 bg-neutral-100 dark:bg-neutral-800 rounded text-neutral-800 dark:text-neutral-200 overflow-x-auto text-[10px] leading-relaxed">
                                {JSON.stringify(currentConfig.motionProps.variants, null, 2)}
                            </pre>
                        </div>
                    </DrawerBody>
                    <DrawerFooter>
                        <Button onClick={onClose}>Close & Animate</Button>
                    </DrawerFooter>
                </DrawerContent>
            </Drawer>
        </div>
    );
};

const SingleSelection = function SingleSelectionStory() {
  const [selected, setSelected] = React.useState<Set<string>>(new Set(["text"]));

  const selectedValue = React.useMemo(
