            {selected && (
              <div className="p-4 bg-primary/5 border border-primary/20 rounded-xl text-sm">
                <span className="font-semibold text-primary">Selected:</span>{" "}
                {selected.name} — {selected.email} — {selected.role}
              </div>
            )}
            <CustomTable
                data={users}
